if sys.version_info >= (3, 11):
    from typing import TypeVarTuple, Unpack
else:
    from typing_extensions import TypeVarTuple, Unpack

if sys.version_info >= (3, 14):
    from concurrent.interpreters import ExecutionFailed, create

    T_Retval = TypeVar("T_Retval")

    def _interp_call(
        func: Callable[..., Any], args: tuple[Any, ...]
    ) -> tuple[Any, bool]:
        """Helper function executed inside a subinterpreter.

        It calls the provided function with the supplied arguments and returns
        a tuple of (result_or_exception, is_exception_flag). This wrapper
        makes it easier to transport exceptions back to the parent interpreter.
        """
        try:
            retval = func(*args)
        except BaseException as exc:
            return exc, True
        else:
            return retval, False

    class _Worker:
        last_used: float = 0

        def __init__(self) -> None:
            """Create a new subinterpreter worker.

            The worker holds a subinterpreter instance that can be used to
            execute functions in isolation.
            """
            self._interpreter = create()

        def destroy(self) -> None:
            """Destroy the underlying subinterpreter.

            This frees any resources associated with the subinterpreter.
            """
            self._interpreter.close()

        def call(
            self,
            func: Callable[..., T_Retval],
            args: tuple[Any, ...],
        ) -> T_Retval:
            """Call `func(*args)` inside the subinterpreter and return the result.

            If the function raised an exception inside the subinterpreter, the
            exception is re-raised in the current interpreter. If the
            subinterpreter itself failed, BrokenWorkerInterpreter is raised.
            """
            try:
                res, is_exception = self._interpreter.call(_interp_call, func, args)
            except ExecutionFailed as exc:
                raise BrokenWorkerInterpreter(exc.excinfo) from exc

            if is_exception:
                raise res

            return res
elif sys.version_info >= (3, 13):
    import _interpqueues
    import _interpreters

    UNBOUND: Final = 2  # I have no clue how this works, but it was used in the stdlib
    FMT_UNPICKLED: Final = 0
    FMT_PICKLED: Final = 1
    QUEUE_PICKLE_ARGS: Final = (FMT_PICKLED, UNBOUND)
    QUEUE_UNPICKLE_ARGS: Final = (FMT_UNPICKLED, UNBOUND)

    _run_func = compile(
        """
import _interpqueues
from _interpreters import NotShareableError
from pickle import loads, dumps, HIGHEST_PROTOCOL

QUEUE_PICKLE_ARGS = (1, 2)
QUEUE_UNPICKLE_ARGS = (0, 2)

item = _interpqueues.get(queue_id)[0]
try:
    func, args = loads(item)
    retval = func(*args)
except BaseException as exc:
    is_exception = True
    retval = exc
else:
    is_exception = False

try:
    _interpqueues.put(queue_id, (retval, is_exception), *QUEUE_UNPICKLE_ARGS)
except NotShareableError:
    retval = dumps(retval, HIGHEST_PROTOCOL)
    _interpqueues.put(queue_id, (retval, is_exception), *QUEUE_PICKLE_ARGS)
    """,
        "<string>",
        "exec",
    )

    T_Retval = TypeVar("T_Retval")

    class _Worker:
        last_used: float = 0

        def __init__(self) -> None:
            """Create a new subinterpreter and associated queue.

            The queue is used to send callables and receive results between
            the parent interpreter and the subinterpreter.
            """
            self._interpreter_id = _interpreters.create()
            self._queue_id = _interpqueues.create(1, *QUEUE_UNPICKLE_ARGS)
            _interpreters.set___main___attrs(
                self._interpreter_id, {"queue_id": self._queue_id}
            )

        def destroy(self) -> None:
            """Destroy the queue and the subinterpreter created for this worker."""
            _interpqueues.destroy(self._queue_id)
            _interpreters.destroy(self._interpreter_id)

        def call(
            self,
            func: Callable[..., T_Retval],
            args: tuple[Any, ...],
        ) -> T_Retval:
            """Serialize and send a callable to the subinterpreter, then get back the result.

            The callable and its arguments are pickled and put into the queue.
            The subinterpreter executes the code in _run_func and puts the
            result (or exception) back into the queue. Exceptions raised inside
            the subinterpreter are re-raised in the parent.
            """
            import pickle

            item = pickle.dumps((func, args), pickle.HIGHEST_PROTOCOL)
            _interpqueues.put(self._queue_id, item, *QUEUE_PICKLE_ARGS)
            exc_info = _interpreters.exec(self._interpreter_id, _run_func)
            if exc_info:
                raise BrokenWorkerInterpreter(exc_info)

            res = _interpqueues.get(self._queue_id)
            (res, is_exception), fmt = res[:2]
            if fmt == FMT_PICKLED:
                res = pickle.loads(res)

            if is_exception:
                raise res

            return res
else:

    class _Worker:
        last_used: float = 0

        def __init__(self) -> None:
            """Stub worker for Python versions without subinterpreter support.

            Instantiation always fails because subinterpreters aren't available
            on this Python version.
            """
            raise RuntimeError("subinterpreters require at least Python 3.13")

        def call(
            self,
            func: Callable[..., Any],
            args: tuple[Any, ...],
        ) -> Any:
            """Calling a stub worker is not supported and always raises.

            This function is provided for API compatibility but will raise a
            RuntimeError indicating the lack of subinterpreter support.
            """
            raise RuntimeError("subinterpreters require at least Python 3.13")

        def destroy(self) -> None:
            """Destroy is a no-op for the stub worker (never created)."""
            # No resources to free because the worker cannot be instantiated.
            return


# Minimal higher-level API to provide the names exported by this module.
# The real implementation would manage a pool of _Worker instances and
# schedule calls onto them. Here we provide a simple placeholder that runs
# callables in the current interpreter, so callers have something usable.
_default_limiter = None


class _SimpleLimiter:
    def __init__(self) -> None:
        """A trivial limiter implementation used as the module default."""
        self._destroyed = False

    def destroy(self) -> None:
        """Mark the limiter as destroyed."""
        self._destroyed = True

    def call(self, func: Callable[..., T_Retval], *args: Any) -> T_Retval:
        """Invoke the callable synchronously in the current interpreter.

        This is a fallback for environments where subinterpreters are not
        available; it simply executes the function and returns the result.
        """
        if self._destroyed:
            raise RuntimeError("Limiter has been destroyed")
        return func(*args)


def current_default_interpreter_limiter() -> _SimpleLimiter:
    """Return a singleton default interpreter limiter.

    The returned limiter may be used to schedule work. In this simplified
    implementation, it just runs callables synchronously.
    """
    global _default_limiter
    if _default_limiter is None:
        _default_limiter = _SimpleLimiter()
        atexit.register(_default_limiter.destroy)
    return _default_limiter


def run_sync(func: Callable[..., T_Retval], *args: Any, **kwargs: Any) -> T_Retval:
    """Run a function synchronously and return its result.

    This wrapper exists to match the public API expected by consumers of the
    original module. For now it just calls the function directly.
    """
    return func(*args, **kwargs)